/// Create a new LLM client with simple scalar configuration.
///
/// This is the primary binding entry-point. All parameters except `api_key`
/// are optional — omitting them uses the same defaults as
/// `ClientConfigBuilder`.
///
/// # Errors
///
/// Returns `LiterLlmError` if the underlying HTTP client cannot be
/// constructed, or if the resolved provider configuration is invalid.
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "createClient")]
pub fn create_client(
    api_key: String,
    base_url: Option<String>,
    timeout_secs: Option<u64>,
    max_retries: Option<u32>,
    model_hint: Option<String>,
) -> Result<WasmDefaultClient, JsValue> {
    let result = liter_llm::create_client(api_key, base_url, timeout_secs, max_retries, model_hint)
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(WasmDefaultClient {
        inner: Arc::new(result),
    })
}

/// Create a new LLM client from a JSON string.
///
/// The JSON object accepts the same fields as `liter-llm.toml` (snake_case).
///
/// # Errors
///
/// Returns `LiterLlmError.BadRequest` if `json` is not valid JSON or
/// contains unknown fields.
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "createClientFromJson")]
pub fn create_client_from_json(json: String) -> Result<WasmDefaultClient, JsValue> {
    let result = liter_llm::create_client_from_json(&json).map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(WasmDefaultClient {
        inner: Arc::new(result),
    })
}

/// Encode bytes as a base64 data URL: `data:<mime>;base64,<b64>`.
///
/// `mime` defaults to `IMAGE_PNG` when `None`.
///
/// # Example
#[wasm_bindgen(js_name = "encodeDataUrl")]
pub fn encode_data_url(bytes: Vec<u8>, mime: Option<String>) -> String {
    liter_llm::image::encode_data_url(&bytes, mime.as_deref())
}

/// Decode a base64 data URL into `DecodedDataUrl`.
///
/// Returns `None` for:
/// - Non-data URLs (strings that do not start with `"data:"`).
/// - Malformed prefixes (missing `";base64,"` marker).
/// - Invalid base64 payloads.
///
/// The returned MIME string is extracted verbatim from the URL prefix —
/// it is not validated or normalised.
///
/// # Example
#[wasm_bindgen(js_name = "decodeDataUrl")]
pub fn decode_data_url(url: String) -> Option<WasmDecodedDataUrl> {
    liter_llm::image::decode_data_url(&url).map(Into::into)
}

/// Register a custom provider in the global runtime registry.
///
/// The provider will be checked **before** all built-in providers during model
/// detection. If a provider with the same `name` already exists it is replaced.
///
/// # Errors
///
/// Returns an error if the config is invalid (empty name, empty base_url, or
/// no model prefixes).
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "registerCustomProvider")]
pub fn register_custom_provider(config: WasmCustomProviderConfig) -> Result<(), JsValue> {
    let config_core: liter_llm::CustomProviderConfig = config.into();

    let result = liter_llm::provider::custom::register_custom_provider(config_core)
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result)
}

/// Remove a previously registered custom provider by name.
///
/// Returns `true` if a provider with the given name was found and removed,
/// `false` if no such provider existed.
///
/// # Errors
///
/// Returns an error if the custom-provider registry cannot be updated.
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "unregisterCustomProvider")]
pub fn unregister_custom_provider(name: String) -> Result<bool, JsValue> {
    let result = liter_llm::provider::custom::unregister_custom_provider(&name)
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result)
}

/// Return the capability flags for a named provider.
///
/// Performs an O(n) linear scan over the embedded registry (143 entries).
/// Returns an owned value so bindings can pass capability data without
/// borrowing registry internals.
///
/// For unknown `provider_name` values the function returns an all-`false`
/// sentinel so callers never need to handle `Option`.
#[wasm_bindgen]
pub fn capabilities(provider_name: String) -> WasmProviderCapabilities {
    liter_llm::provider::capabilities(&provider_name).into()
}

/// Return all provider configs from the registry.
///
/// Useful for tooling, documentation generation, or runtime enumeration.
/// Returns the public `ProviderConfig` slice (without capability flags).
/// To query capability flags for a specific provider use `capabilities`.
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "allProviders")]
pub fn all_providers() -> Result<Vec<WasmProviderConfig>, JsValue> {
    let result = liter_llm::provider::all_providers().map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result.iter().map(|v| v.clone().into()).collect())
}

/// Return the set of complex provider names.
///
/// Complex providers require custom auth/routing logic beyond simple bearer
/// tokens (e.g. AWS Bedrock SigV4, Vertex AI OAuth2).
///
/// The returned reference points into the static registry — no allocation.
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "complexProviderNames")]
pub fn complex_provider_names() -> Result<Vec<String>, JsValue> {
    let result = liter_llm::provider::complex_provider_names().map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result.iter().map(|s| s.to_string()).collect())
}

/// Calculate the estimated cost of a completion given a model name and token
/// counts.
///
/// Returns `None` if the model is not present in the embedded pricing registry.
/// Returns `Some(cost_usd)` otherwise, where the value is in US dollars.
///
/// When an exact model name match is not found, progressively shorter prefixes
/// are tried by stripping from the last `-` or `.` separator.  For example,
/// `gpt-4-0613` will match `gpt-4` if no `gpt-4-0613` entry exists.
///
/// # Example
#[wasm_bindgen(js_name = "completionCost")]
pub fn completion_cost(model: String, prompt_tokens: u64, completion_tokens: u64) -> Option<f64> {
    liter_llm::completion_cost(&model, prompt_tokens, completion_tokens)
}

/// Calculate the estimated cost of a completion, accounting for cached
/// (cache-hit) prompt tokens billed at the provider's discounted rate.
///
/// `cached_tokens` is the count of prompt tokens served from the provider's
/// prompt cache. It must be `<= prompt_tokens` (cached tokens are a subset of
/// the prompt). The non-cached portion is billed at `input_cost_per_token`
/// and the cached portion at `cache_read_input_token_cost` when the model
/// has cache pricing; otherwise the entire prompt is billed at the regular
/// input rate.
///
/// Returns `None` if the model is not present in the embedded pricing
/// registry, mirroring `completion_cost`.
#[wasm_bindgen(js_name = "completionCostWithCache")]
pub fn completion_cost_with_cache(
    model: String,
    prompt_tokens: u64,
    cached_tokens: u64,
    completion_tokens: u64,
) -> Option<f64> {
    liter_llm::completion_cost_with_cache(&model, prompt_tokens, cached_tokens, completion_tokens)
}

/// Remove all guardrails from the global registry.
///
